def calculate_total(items):
    total = 0
    for item in items:
        total += item['price'] * item['quantity']
    return total

def validate_item(item):
    if 'name' not in item or not item['name']:
        return False
    if 'price' not in item or item['price'] <= 0:
        return False
    if 'quantity' not in item or item['quantity'] <= 0:
        return False
    return True

def process_order(order):
    for item in order:
        if not validate_item(item):
            return "Order failed: Invalid item in order"
    total_price = calculate_total(order)
    return f"Order processed successfully! Total: ${total_price:.2f}"

if __name__ == '__main__':
    sample_order = [
        {'name': 'Laptop', 'price': 1200.00, 'quantity': 1},
        {'name': 'Mouse', 'price': 25.50, 'quantity': 2},
    ]
    print(process_order(sample_order))

    invalid_order = [
        {'name': 'Keyboard', 'price': 75, 'quantity': 1},
        {'name': 'USB Hub', 'price': -10, 'quantity': 1},
    ]
    print(process_order(invalid_order))

